<div class="card"><div class="actions" style="justify-content:space-between;align-items:center"><div><h2>用户日志</h2><p class="muted">用户：<?=h($x['username'])?> #<?=h($x['id'])?>，共 <?=h($total)?> 条</p></div><a class="btn" href="index.php?r=admin">返回后台</a></div></div><div class="card"><div class="table-wrap"><table><thead><tr><th>时间</th><th>状态</th><th>步数</th><th>结果</th></tr></thead><tbody><?php if(empty($logs)): ?><tr><td colspan="4" class="muted">暂无日志</td></tr><?php else: ?><?php foreach($logs as $log): ?><tr><td><?=h($log['created_at'])?></td><td><span class="badge <?=$log['status']==='success'?'ok':'bad'?>"><?=h($log['status']==='success'?'成功':($log['status']==='skipped'?'跳过':'失败'))?></span></td><td><?=h($log['steps']!==null&&$log['steps']!==''?$log['steps']:'-')?></td><td><?=h($log['message'])?></td></tr><?php endforeach; ?><?php endif; ?></tbody></table></div><div class="actions" style="justify-content:center;margin-top:16px"><?php if($page>1): ?><a class="btn light" href="index.php?r=admin_user_logs&id=<?=h($x['id'])?>&page=<?=$page-1?>">上一页</a><?php endif; ?><span class="btn gray">第 <?=$page?> / <?=$pages?> 页</span><?php if($page<$pages): ?><a class="btn light" href="index.php?r=admin_user_logs&id=<?=h($x['id'])?>&page=<?=$page+1?>">下一页</a><?php endif; ?></div></div>